sql:
SELECT *
FROM player_game_logs
WHERE player_id > 0 AND game_id > 100;

SELECT players.player_name, teams.team_name, players.position 
FROM players
INNER JOIN teams ON players.team_id = teams.team_id;

SELECT player_id
FROM user_players
WHERE user_id = 0;

SELECT p.player_name, s.touchdowns
FROM players p
JOIN stats s ON p.player_id = s.player_id
WHERE s.touchdowns = (
    SELECT MAX(touchdowns) FROM stats
);
